import java.io.*;
import java.nio.file.*;

public class Main {
    static class Rule {
        String name;
        double oka;
        double[] uma;
        int originPt;
        Rule(String name, double oka, double[] uma, int originPt) {
            this.name = name; this.oka = oka; this.uma = uma; this.originPt = originPt;
        }
    }

    static Rule getRule(String ruleName) {
        if (ruleName == null) ruleName = "";
        String r = ruleName.toLowerCase();
        if (r.contains("wrc")) return new Rule("WRC", 0.0, new double[]{15.0, 5.0, -5.0, -15.0}, 30000);
        else if (r.contains("a规") || r.equals("a")) return new Rule("A规", 0.0, new double[]{15.0, 5.0, -5.0, -15.0}, 30000);
        else if (r.contains("最高位")) return new Rule("最高位战", 0.0, new double[]{30.0, 10.0, -10.0, -30.0}, 30000);
        return new Rule("M-league", 20.0, new double[]{50.0, 10.0, -10.0, -30.0}, 30000); 
    }

    static class Player {
        String name;
        int seatIdx;
        double startPt;
        int score;
        Player(String name, int seatIdx, double startPt, int score) {
            this.name = name; this.seatIdx = seatIdx; this.startPt = startPt; this.score = score;
        }
    }

    static class GameState {
        Player[] players = new Player[4];
        int dealerIdx;
        int advanceN;
        Rule rule;
        int kyoutaku;
        int honba;
    }

    static List<Integer> ronC = new ArrayList<>();
    static List<Integer> ronD = new ArrayList<>();
    static List<int[]> tsC = new ArrayList<>();
    static List<Integer> tsD = new ArrayList<>();

    static int ceil100(int x) { return ((x + 99) / 100) * 100; }

    static int getBase(int han, int fu) {
        if (han == 1 && fu < 30) return 0;
        if (han == 2 && fu == 20) return 0;
        if (han >= 13) return 8000 * (han / 13);
        if (han >= 11) return 6000;
        if (han >= 8) return 4000;
        if (han >= 6) return 3000;
        if (han == 5) return 2000;
        int a = fu * (1 << (han + 2));
        return a >= 2000 ? 2000 : a;
    }

    static {
        Set<Integer> rc = new TreeSet<>();
        Set<Integer> rd = new TreeSet<>();
        Set<String> tc = new HashSet<>();
        Set<Integer> td = new TreeSet<>();

        for (int han = 1; han < 40; han++) {
            int[] fus = {20, 25, 30, 40, 50, 60, 70, 80, 90, 100, 110};
            for (int fu : fus) {
                int b = getBase(han, fu);
                if (b == 0) continue;
                rc.add(ceil100(b * 4));
                rd.add(ceil100(b * 6));
                int dPays = ceil100(b * 2);
                int cPays = ceil100(b * 1);
                tc.add(dPays + "," + cPays);
                td.add(ceil100(b * 2));
            }
        }
        ronC.addAll(rc);
        ronD.addAll(rd);
        for (String s : tc) {
            String[] parts = s.split(",");
            tsC.add(new int[]{Integer.parseInt(parts[0]), Integer.parseInt(parts[1])});
        }
        tsC.sort((a, b) -> Integer.compare(a[0] + a[1]*2, b[0] + b[1]*2));
        tsD.addAll(td);
    }

    static String formatTsumoName(int valD, int valC, boolean isDealerWin) {
        if (isDealerWin) {
            if (valD == 4000) return "满贯all";
            if (valD == 6000) return "跳满all";
            if (valD == 8000) return "倍满all";
            if (valD == 12000) return "3倍满all";
            if (valD == 16000) return "役满all";
            if (valD == 32000) return "2倍役满all";
            if (valD == 48000) return "3倍役满all";
            return valD + "all";
        } else {
            if (valD == 8000 && valC == 4000) return "满贯";
            if (valD == 12000 && valC == 6000) return "跳满";
            if (valD == 16000 && valC == 8000) return "倍满";
            if (valD == 24000 && valC == 12000) return "3倍满";
            if (valD == 32000 && valC == 16000) return "役满";
            if (valD == 64000 && valC == 32000) return "2倍役满";
            if (valD == 96000 && valC == 48000) return "3倍役满";
            return valC + "・" + valD;
        }
    }

    static String formatRonName(int val, boolean isDealer) {
        if (isDealer) {
            if (val == 48000) return "役满";
            if (val == 96000) return "2倍役满";
            if (val == 144000) return "3倍役满";
        } else {
            if (val == 32000) return "役满";
            if (val == 64000) return "2倍役满";
            if (val == 96000) return "3倍役满";
        }
        return String.valueOf(val);
    }

    static boolean checkAdvance(GameState st, int targetIdx, int[] scores) {
        double[] pt = new double[4];
        Integer[] pIdx = {0, 1, 2, 3};
        Arrays.sort(pIdx, (a, b) -> {
            if (scores[a] != scores[b]) return Integer.compare(scores[b], scores[a]);
            return Integer.compare(st.players[a].seatIdx, st.players[b].seatIdx);
        });

        int[] ranks = new int[4];
        for (int i = 0; i < 4; i++) ranks[pIdx[i]] = i;

        for (int i = 0; i < 4; i++) {
            pt[i] = st.players[i].startPt + (scores[i] - st.rule.originPt) / 1000.0 + st.rule.uma[ranks[i]];
        }

        Integer[] ptIdx = {0, 1, 2, 3};
        Arrays.sort(ptIdx, (a, b) -> {
            if (pt[a] != pt[b]) return Double.compare(pt[b], pt[a]);
            return Integer.compare(st.players[a].seatIdx, st.players[b].seatIdx);
        });

        for (int i = 0; i < st.advanceN; i++) {
            if (ptIdx[i] == targetIdx) return true;
        }
        return false;
    }

    static String formatInterval(int minIdx, int maxIdx, List<Integer> scores, boolean isDealer) {
        if (minIdx == 0 && maxIdx == scores.size() - 1) {
            return formatRonName(scores.get(maxIdx), isDealer) + "以下会丢晋级资格";
        } else if (minIdx == 0) {
            return formatRonName(scores.get(maxIdx), isDealer) + "以下会丢晋级资格";
        } else if (maxIdx == scores.size() - 1) {
            String v1 = formatRonName(scores.get(minIdx), isDealer);
            if (v1.equals("24000") || v1.equals("18000") || v1.equals("8000")) {
                return v1 + "以上3倍役满以下会丢晋级资格";
            }
            if (v1.equals("役满")) return v1 + "以上3倍役满以下会丢晋级资格";
            return v1 + "以上会丢晋级资格";
        } else {
            return formatRonName(scores.get(minIdx), isDealer) + "以上" + formatRonName(scores.get(maxIdx), isDealer) + "以下会丢晋级资格";
        }
    }
