    static List<Integer> ronD = new ArrayList<>();
    static List<int[]> tsC = new ArrayList<>();
    static List<Integer> tsD = new ArrayList<>();

    static int ceil100(int x) { return ((x + 99) / 100) * 100; }

    static int getBase(int han, int fu) {
        if (han == 1 && fu < 30) return 0;
        if (han == 2 && fu == 20) return 0;
        if (han >= 13) return 8000 * (han / 13);
        if (han >= 11) return 6000;
        if (han >= 8) return 4000;
        if (han >= 6) return 3000;
        if (han == 5) return 2000;
        int a = fu * (1 << (han + 2));
        return a >= 2000 ? 2000 : a;
    }

    static {
        Set<Integer> rc = new TreeSet<>();
        Set<Integer> rd = new TreeSet<>();
        Set<String> tc = new HashSet<>();
        Set<Integer> td = new TreeSet<>();

        for (int han = 1; han < 40; han++) {
            int[] fus = {20, 25, 30, 40, 50, 60, 70, 80, 90, 100, 110};
            for (int fu : fus) {
                int b = getBase(han, fu);
                if (b == 0) continue;
                rc.add(ceil100(b * 4));
                rd.add(ceil100(b * 6));
                int dPays = ceil100(b * 2);
                int cPays = ceil100(b * 1);
                tc.add(dPays + "," + cPays);
                td.add(ceil100(b * 2));
            }
        }
        ronC.addAll(rc);
        ronD.addAll(rd);
